-- 세그먼트 공간 사용 현황 분석
DECLARE
  l_unformatted_blocks  NUMBER;
  l_unformatted_bytes   NUMBER;
  l_fs1_blocks          NUMBER; -- 0-25% 사용
  l_fs1_bytes           NUMBER;
  l_fs2_blocks          NUMBER; -- 25-50% 사용
  l_fs2_bytes           NUMBER;
  l_fs3_blocks          NUMBER; -- 50-75% 사용
  l_fs3_bytes           NUMBER;
  l_fs4_blocks          NUMBER; -- 75-100% 사용
  l_fs4_bytes           NUMBER;
  l_full_blocks         NUMBER; -- 100% 사용
  l_full_bytes          NUMBER;
BEGIN
  DBMS_SPACE.SPACE_USAGE(
    segment_owner      => 'HR',
    segment_name       => 'EMPLOYEES',
    segment_type       => 'TABLE',
    unformatted_blocks => l_unformatted_blocks,
    unformatted_bytes  => l_unformatted_bytes,
    fs1_blocks         => l_fs1_blocks,
    fs1_bytes          => l_fs1_bytes,
    fs2_blocks         => l_fs2_blocks,
    fs2_bytes          => l_fs2_bytes,
    fs3_blocks         => l_fs3_blocks,
    fs3_bytes          => l_fs3_bytes,
    fs4_blocks         => l_fs4_blocks,
    fs4_bytes          => l_fs4_bytes,
    full_blocks        => l_full_blocks,
    full_bytes         => l_full_bytes
  );
  DBMS_OUTPUT.PUT_LINE('Full Blocks (100%):    ' || l_full_blocks);
  DBMS_OUTPUT.PUT_LINE('75-100% Used Blocks:   ' || l_fs4_blocks);
  DBMS_OUTPUT.PUT_LINE('50-75% Used Blocks:    ' || l_fs3_blocks);
  DBMS_OUTPUT.PUT_LINE('25-50% Used Blocks:    ' || l_fs2_blocks);
  DBMS_OUTPUT.PUT_LINE('0-25% Used Blocks:     ' || l_fs1_blocks);
  DBMS_OUTPUT.PUT_LINE('Unformatted Blocks:    ' || l_unformatted_blocks);
END;
/

-- 세그먼트 크기 대비 실제 데이터 비율 확인
SELECT s.segment_name,
       s.bytes / 1024 / 1024 AS segment_size_mb,
       t.num_rows * t.avg_row_len / 1024 / 1024 AS estimated_data_mb,
       ROUND((1 - (t.num_rows * t.avg_row_len) / NULLIF(s.bytes, 0)) * 100, 1) AS waste_pct
FROM   dba_segments s
JOIN   dba_tables t ON s.segment_name = t.table_name AND s.owner = t.owner
WHERE  s.owner = 'HR'
  AND  s.segment_type = 'TABLE'
ORDER BY waste_pct DESC;

-- 1. 현재 세그먼트 크기 확인
SELECT segment_name, bytes / 1024 / 1024 AS size_mb, blocks
FROM   dba_segments
WHERE  owner = 'HR' AND segment_name = 'EMPLOYEES';

-- 2. ROW MOVEMENT 활성화 (SHRINK 전제조건)
ALTER TABLE hr.employees ENABLE ROW MOVEMENT;

-- 3. ROW MOVEMENT 상태 확인
SELECT table_name, row_movement
FROM   dba_tables
WHERE  owner = 'HR' AND table_name = 'EMPLOYEES';
-- 결과: ROW_MOVEMENT = 'ENABLED'

-- 4-A. SHRINK SPACE 실행 (데이터 재배치 + HWM 하향)
ALTER TABLE hr.employees SHRINK SPACE;

-- 4-B. 또는 2단계 전략 (업무 시간 / 유지보수 시간 분리)
-- 업무 시간: 데이터 재배치만 (DML 영향 최소)
ALTER TABLE hr.employees SHRINK SPACE COMPACT;
-- 유지보수 시간: HWM 하향 (짧은 Exclusive Lock)
ALTER TABLE hr.employees SHRINK SPACE;

-- 4-C. CASCADE 옵션 (종속 인덱스도 함께 축소)
ALTER TABLE hr.employees SHRINK SPACE CASCADE;

-- 5. 축소 후 세그먼트 크기 확인
SELECT segment_name, bytes / 1024 / 1024 AS size_mb, blocks
FROM   dba_segments
WHERE  owner = 'HR' AND segment_name = 'EMPLOYEES';

-- 방법 1: SHRINK SPACE로 해결 (온라인, 추가 공간 불필요)
ALTER TABLE hr.employees ENABLE ROW MOVEMENT;
ALTER TABLE hr.employees SHRINK SPACE;

-- 방법 2: ALTER TABLE MOVE로 해결 (테이블 재구성)
-- 오프라인 MOVE (인덱스 REBUILD 필요)
ALTER TABLE hr.employees MOVE;
-- 인덱스 상태 확인
SELECT index_name, status FROM dba_indexes
WHERE table_name = 'EMPLOYEES' AND owner = 'HR';
-- UNUSABLE 인덱스 REBUILD
ALTER INDEX hr.emp_pk REBUILD;
ALTER INDEX hr.emp_name_idx REBUILD;

-- 온라인 MOVE (인덱스 자동 유지, 12c R2+)
ALTER TABLE hr.employees MOVE ONLINE;

-- 방법 3: PCTFREE 증가 후 MOVE로 향후 Migration 방지
ALTER TABLE hr.employees PCTFREE 20;
ALTER TABLE hr.employees MOVE ONLINE;

-- 해결 후 Migration 상태 재확인
TRUNCATE TABLE chained_rows;
ANALYZE TABLE hr.employees LIST CHAINED ROWS INTO chained_rows;
SELECT COUNT(*) AS remaining_chained_rows FROM chained_rows
WHERE table_name = 'EMPLOYEES';

-- 1. 압축 테이블 생성
CREATE TABLE hr.employees_compressed
  ROW STORE COMPRESS BASIC
AS SELECT * FROM hr.employees WHERE 1=0;

-- 2. Direct-Path Insert로 압축 적재
INSERT /*+ APPEND */ INTO hr.employees_compressed
SELECT * FROM hr.employees;
COMMIT;

-- 3. 기존 테이블에 압축 적용 (ALTER TABLE MOVE)
ALTER TABLE hr.sales_history MOVE ROW STORE COMPRESS BASIC;

-- 4. CTAS로 압축 테이블 생성
CREATE TABLE hr.orders_archive
  ROW STORE COMPRESS BASIC
  TABLESPACE archive_ts
AS SELECT * FROM hr.orders WHERE order_date < DATE '2024-01-01';

-- 5. 압축 상태 확인
SELECT table_name, compression, compress_for
FROM   dba_tables
WHERE  owner = 'HR'
  AND  table_name IN ('EMPLOYEES_COMPRESSED', 'SALES_HISTORY', 'ORDERS_ARCHIVE');

-- 6. 압축률 사전 추정
DECLARE
  l_compression_ratio  NUMBER;
  l_compressed_blocks  NUMBER;
  l_uncompressed_blocks NUMBER;
  l_rows_sampled       NUMBER;
BEGIN
  DBMS_COMPRESSION.GET_COMPRESSION_RATIO(
    scratchtbsname  => 'USERS',
    ownname         => 'HR',
    objname         => 'EMPLOYEES',
    subobjname      => NULL,
    comptype        => DBMS_COMPRESSION.COMP_BASIC,
    blkcnt_cmp      => l_compressed_blocks,
    blkcnt_uncmp    => l_uncompressed_blocks,
    row_cmp         => l_rows_sampled,
    row_uncmp       => l_rows_sampled,
    cmp_ratio       => l_compression_ratio
  );
  DBMS_OUTPUT.PUT_LINE('Compression Ratio: ' || ROUND(l_compression_ratio, 2) || 'x');
END;
/

-- 1. Direct-Path Insert (APPEND 힌트)
INSERT /*+ APPEND */ INTO hr.target_table
SELECT * FROM hr.source_table;
COMMIT;

-- 2. CTAS (Create Table As Select) - 자동 Direct-Path
CREATE TABLE hr.target_ctas AS
SELECT * FROM hr.source_table;

-- 3. 병렬 Direct-Path Insert
ALTER SESSION ENABLE PARALLEL DML;
INSERT /*+ APPEND PARALLEL(t, 4) */ INTO hr.target_table t
SELECT /*+ PARALLEL(s, 4) */ * FROM hr.source_table s;
COMMIT;

-- 4. Direct-Path Insert 확인 (V$SQL 통계)
SELECT sql_id, sql_text, direct_writes
FROM   v$sql
WHERE  sql_text LIKE '%APPEND%target_table%'
  AND  ROWNUM <= 5;

-- 5. HWM 위 기록 확인 (세그먼트 크기 변화)
SELECT segment_name, blocks, bytes / 1024 / 1024 AS size_mb
FROM   dba_segments
WHERE  owner = 'HR' AND segment_name = 'TARGET_TABLE';

-- 1. 테이블 NOLOGGING 설정
ALTER TABLE hr.staging_table NOLOGGING;

-- NOLOGGING 상태 확인
SELECT table_name, logging
FROM   dba_tables
WHERE  owner = 'HR' AND table_name = 'STAGING_TABLE';
-- 결과: LOGGING = 'NO'

-- 2. Redo 생성량 확인 (적재 전)
SELECT value AS redo_before FROM v$mystat ms
JOIN   v$statname sn ON ms.statistic# = sn.statistic#
WHERE  sn.name = 'redo size';

-- 3. NOLOGGING + Direct-Path Insert 실행
INSERT /*+ APPEND */ INTO hr.staging_table
SELECT * FROM hr.large_source_table;
COMMIT;

-- 4. Redo 생성량 확인 (적재 후)
SELECT value AS redo_after FROM v$mystat ms
JOIN   v$statname sn ON ms.statistic# = sn.statistic#
WHERE  sn.name = 'redo size';

-- 5. FORCE LOGGING 확인 (DB/테이블스페이스 레벨)
SELECT force_logging FROM v$database;
SELECT tablespace_name, force_logging
FROM   dba_tablespaces
WHERE  tablespace_name = 'USERS';

-- 6. 적재 완료 후 LOGGING으로 복원 (권장)
ALTER TABLE hr.staging_table LOGGING;

-- 7. Data Guard 환경에서 NOLOGGING 블록 확인
SELECT file#, block#, blocks
FROM   v$datafile_header
WHERE  unrecoverable_change# > 0;

-- 1. 인덱스를 UNUSABLE로 설정
ALTER INDEX hr.emp_dept_idx UNUSABLE;

-- 2. 인덱스 상태 확인
SELECT index_name, status, segment_created
FROM   dba_indexes
WHERE  owner = 'HR' AND index_name = 'EMP_DEPT_IDX';
-- 결과: STATUS = 'UNUSABLE', SEGMENT_CREATED = 'NO' (세그먼트 삭제됨)

-- 3. SKIP_UNUSABLE_INDEXES 확인
SHOW PARAMETER skip_unusable_indexes;
-- 결과: TRUE (기본값) → UNUSABLE 인덱스가 있어도 DML 가능

-- 4. UNUSABLE 상태에서 DML 수행 (SKIP_UNUSABLE_INDEXES=TRUE)
INSERT INTO hr.employees (employee_id, last_name, department_id)
VALUES (999, 'TEST', 10);  -- 정상 수행
COMMIT;

-- 5. 인덱스 REBUILD
ALTER INDEX hr.emp_dept_idx REBUILD;

-- 온라인 REBUILD
ALTER INDEX hr.emp_dept_idx REBUILD ONLINE;

-- 다른 테이블스페이스에 REBUILD
ALTER INDEX hr.emp_dept_idx REBUILD TABLESPACE new_idx_ts;

-- 병렬 + NOLOGGING REBUILD
ALTER INDEX hr.emp_dept_idx REBUILD PARALLEL 4 NOLOGGING;

-- 6. REBUILD 후 상태 확인
SELECT index_name, status, segment_created, tablespace_name
FROM   dba_indexes
WHERE  owner = 'HR' AND index_name = 'EMP_DEPT_IDX';
-- 결과: STATUS = 'VALID', SEGMENT_CREATED = 'YES'
